@import url('https://fonts.googleapis.com/css2?family=Syncopate:wght@400;700&display=swap');

/* Hero Section Wrapper - Full Viewport Height */
.hero-section-wrapper {
    position: relative;
    width: 100%;
    height: 100vh;
    display: flex;
    align-items: center;
    justify-content: center;
    overflow: visible;
}

/* Himalayan Shader Background - Absolute within hero wrapper */
.himalayan-shader-bg {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: 0;
}

.himalayan-shader-bg canvas {
    width: 100% !important;
    height: 100% !important;
}

/* Hero Section Container */
.hero-container {
    position: relative;
    width: 100%;
    max-width: 1400px;
    height: 100svh;
    /* use small viewport height for mobile */
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    /* Center align on mobile */
    padding: 1rem 1rem 0 1rem;
    background-color: transparent;
    overflow: hidden;
    /* Prevent scroll within hero */
}

@media (min-width: 768px) {
    .hero-container {
        width: 90%;
        height: 85vh;
        align-items: flex-start;
        padding-left: 3rem;
        padding-right: 6rem;
        overflow: visible;
    }
}

/* Canvas Wrapper (3D Model) */
.hero-canvas-wrapper {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    z-index: 10;
    /* Behind the text */
    pointer-events: none;
}

/* We need pointer events on the canvas for OrbitControls */
.hero-canvas-wrapper {
    pointer-events: auto;
}

/* Specific styling for the frosted text container to position it correctly */
.frosted-text-container {
    position: absolute;
    top: 10%;
    /* Moved up significantly per user request */
    left: 50%;
    transform: translateX(-50%);
    /* Center horizontally on mobile */
    z-index: 20;
    width: 95%;
    /* Use more width */
    text-align: center;
    pointer-events: none;
    /* Let clicks pass through to canvas if needed */
}

/* Right-side text container */
.frosted-text-container-right {
    position: absolute;
    /* Right-side text container - On mobile, this holds the button/subtext */
    bottom: 2%;
    /* Lowered to absolute bottom edge per user request */
    right: 5%;
    /* Dock to right */
    left: auto;
    transform: none;
    /* Remove centering */
    z-index: 20;
    text-align: right;
    /* Right align text */
    width: 50%;
    /* Constrict width */
    max-width: 200px;
    pointer-events: auto;
    display: flex;
    flex-direction: column;
    align-items: flex-end;
    /* Ensure button aligns right */
}

/* Frosted Glass Button */
.frosted-glass-button {
    /* Typography matching Syncopate style */
    font-family: 'Syncopate', sans-serif;
    font-size: 0.75rem;
    /* Reduced size */
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.1em;

    /* Button Structure */
    margin-top: 0.8rem;
    padding: 0.6rem 0.8rem;
    /* Reduced padding */
    cursor: pointer;
    border: 1px solid rgba(255, 255, 255, 0.4);
    border-radius: 18px;
    background: rgba(255, 255, 255, 0.05);
    backdrop-filter: blur(5px);
    transition: all 0.3s ease;

    /* Text Color */
    color: #ffffff;
    /* Proper solid white */
    background: transparent;
    /* Remove gradient background */
    -webkit-background-clip: border-box;
    background-clip: border-box;

    /* Glow */
    box-shadow: 0 0 10px rgba(255, 255, 255, 0.1);
}

.frosted-glass-button:hover {
    color: rgba(255, 255, 255, 0.95);
    background: rgba(255, 255, 255, 0.15);
    background-clip: padding-box;
    -webkit-background-clip: padding-box;
    border-color: rgba(255, 255, 255, 0.8);
    box-shadow: 0 0 20px rgba(255, 255, 255, 0.3);
}

/* Frosted Glass Text Effect & Typography */
.frosted-glass-text {
    /* Typography */
    font-family: 'Syncopate', sans-serif;
    font-size: clamp(3.25rem, 11vw, 4.5rem);
    /* Increased by 30% (was 2.5rem) */
    /* Responsive font size */
    line-height: 1.2;
    /* Looser leading */
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    margin: 0;

    /* Base color transparent for gradient clip */
    color: transparent;

    /* Gradient Fill for Icy Look */
    background: linear-gradient(180deg,
            rgba(255, 255, 255, 0.95) 0%,
            rgba(255, 255, 255, 0.5) 50%,
            rgba(255, 255, 255, 0.1) 100%);

    /* Clip background to text */
    -webkit-background-clip: text;
    background-clip: text;

    /* Glassy Glow/Shadow */
    filter: drop-shadow(0 0 15px rgba(255, 255, 255, 0.35));
}

/* Right-side smaller regular text styling */
.frosted-glass-text-right {
    /* Inherits Font from global but specific settings here */
    font-family: 'Syncopate', sans-serif;
    font-size: clamp(0.5rem, 2.5vw, 0.8rem);
    /* Responsive font size - Decreased significantly */
    line-height: 1.4;
    font-weight: 400;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    margin: 0;

    /* Same Frosted Effect - MODIFIED for Visibility */
    color: #ffffff;
    /* Solid white */
    background: none;
    /* Remove gradient */
    -webkit-background-clip: border-box;
    background-clip: border-box;
    text-shadow: 0 2px 8px rgba(0, 0, 0, 0.6);
    /* Strong dark shadow for contrast */
    filter: none;
    /* Remove glow filter */
}

/* Center Bottom Text Image */
.center-bottom-text {
    position: absolute;
    bottom: 0.5%;
    /* Reduced further as per user request */
    left: 48%;
    transform: translateX(-50%) translateY(10%);
    /* Moved up by reducing Y translation */
    z-index: 20;
    pointer-events: auto;
    width: 100%;
    /* Ensure full width available */
    display: flex;
    justify-content: center;
}

.center-bottom-text img,
.center-bottom-text canvas {
    width: 100%;
    /* Adjusted width */
    max-width: 850px;
    /* Reduced max width */
    height: auto;
    opacity: 0.9;
    filter: drop-shadow(0 6px 16px rgba(60, 60, 60, 0.45));
    cursor: pointer;
}

/* Responsive adjustments (Desktop) */
@media (min-width: 768px) {
    .frosted-text-container {
        top: 5rem;
        left: 1.5rem;
        transform: none;
        width: auto;
        text-align: left;
    }

    .frosted-glass-text {
        font-size: 4rem;
        /* text-6xl */
    }

    .frosted-text-container-right {
        right: 1.5rem;
        left: auto;
        transform: none;
        bottom: 5rem;
        text-align: right;
        max-width: 600px;
    }

    .frosted-glass-text-right {
        font-size: 2.2rem;
    }

    .center-bottom-text canvas {
        max-width: 750px;
    }
}

/* Specific Adjustment for Center Bottom Text on Mobile */
@media (max-width: 768px) {
    .center-bottom-text {
        width: 90%;
        bottom: 8%;
        /* Gave a bit more breathing room from bottom edge */
        transform: translateX(-50%);
        /* Removed vertical translate */
    }

    .center-bottom-text img,
    .center-bottom-text canvas {
        width: 100%;
        max-width: 300px;
    }
}

/* =========================================
   Workshop Gallery Section Styling
   ========================================= */

.workshop-gallery-section {
    position: relative;
    width: 100%;
    background-color: #f8f9fa;
    padding-top: 0;
    padding-bottom: 0.5rem;
    overflow: hidden;
}

.workshop-gallery-mist {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 2rem;
    background: linear-gradient(to bottom, #ffffff, transparent);
    pointer-events: none;
    z-index: 10;
}

.workshop-container {
    max-width: 80rem;
    /* 7xl */
    margin-left: auto;
    margin-right: auto;
    padding-left: 1.5rem;
    padding-right: 1.5rem;
}

@media (min-width: 768px) {
    .workshop-container {
        padding-left: 3rem;
        padding-right: 3rem;
    }
}

/* Gallery Item Row */
.gallery-item-row {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 3rem;
    margin-bottom: 8rem;
}

@media (min-width: 768px) {
    .gallery-item-row {
        flex-direction: row;
        gap: 6rem;
    }

    .gallery-item-row.reverse {
        flex-direction: row-reverse;
    }
}

/* Text Column */
.gallery-text-col {
    flex: 1;
    z-index: 10;
    text-align: center;
}

.gallery-text-col>*+* {
    margin-top: 1.5rem;
    /* space-y-6 equivalent */
}

@media (min-width: 768px) {
    .gallery-text-col {
        text-align: left;
    }
}

.gallery-title {
    font-family: serif;
    /* Ensure you have a serif font loaded or fallback */
    font-size: 2.25rem;
    /* 4xl */
    line-height: 1;
    font-weight: 300;
    /* font-light */
    color: #1e293b;
    /* slate-800 */
    letter-spacing: -0.025em;
    /* tracking-tight */
}

@media (min-width: 768px) {
    .gallery-title {
        font-size: 3rem;
        /* 5xl */
    }
}

.gallery-divider {
    width: 4rem;
    height: 0.25rem;
    background-color: rgba(6, 182, 212, 0.3);
    /* cyan-500/30 */
    border-radius: 9999px;
    margin-left: auto;
    margin-right: auto;
}

@media (min-width: 768px) {
    .gallery-divider {
        margin-left: 0;
        margin-right: 0;
    }
}

.gallery-desc {
    font-size: 1.125rem;
    /* lg */
    color: #475569;
    /* slate-600 */
    line-height: 1.625;
    /* leading-relaxed */
    font-weight: 300;
    /* font-light */
    max-width: 32rem;
    /* max-w-lg */
    margin-left: auto;
    margin-right: auto;
}

@media (min-width: 768px) {
    .gallery-desc {
        margin-left: 0;
        margin-right: 0;
    }
}

/* Button */
.gallery-btn {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    margin-top: 1rem;
    padding: 0.75rem 2rem;
    background-color: white;
    border: 1px solid #e2e8f0;
    /* slate-200 */
    border-radius: 9999px;
    box-shadow: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
    transition: all 300ms;
    cursor: pointer;
    margin-left: auto;
    margin-right: auto;
}

@media (min-width: 768px) {
    .gallery-btn {
        margin-left: 0;
        margin-right: 0;
    }
}

.gallery-btn:hover {
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
}

.gallery-btn-text {
    font-weight: 500;
    background: linear-gradient(to right, #1e293b, #475569);
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
}

.gallery-btn-dot {
    width: 0.5rem;
    height: 0.5rem;
    border-radius: 9999px;
    background-color: #22d3ee;
    /* cyan-400 */
    transition: transform 300ms;
}

.gallery-btn:hover .gallery-btn-dot {
    transform: scale(1.25);
}

/* Visual Column */
.gallery-visual-col {
    flex: 1;
    width: 100%;
    position: relative;
    /* group functionality handled in CSS via nesting or parent selector if needed, 
       but standard CSS :hover on parent works */
}

.gallery-glow {
    position: absolute;
    inset: -1rem;
    background: linear-gradient(to top right, rgba(207, 250, 254, 0.5), rgba(239, 246, 255, 0.5));
    border-radius: 2rem;
    filter: blur(40px);
    opacity: 0;
    transition: opacity 700ms;
    pointer-events: none;
}

.gallery-visual-col:hover .gallery-glow {
    opacity: 1;
}

.gallery-media-container {
    position: relative;
    width: 100%;
    aspect-ratio: 4/3;
    border-radius: 2rem;
    overflow: hidden;
    background-color: white;
    /* Fallback */
    border: 1px solid rgba(255, 255, 255, 0.5);
    transition: box-shadow 500ms;
    box-shadow: 0 20px 50px -12px rgba(200, 210, 230, 0.6);
}

@media (min-width: 768px) {
    .gallery-media-container {
        aspect-ratio: 1 / 1;
    }
}

.gallery-visual-col:hover .gallery-media-container {
    box-shadow: 0 20px 50px -12px rgba(164, 213, 255, 0.4);
}

/* Placeholders */
.gallery-placeholder-inner {
    position: absolute;
    inset: 0;
    display: flex;
    align-items: center;
    justify-content: center;
}

.placeholder-icon-box {
    display: inline-block;
    padding: 1rem;
    border-radius: 9999px;
    background-color: rgba(255, 255, 255, 0.3);
    backdrop-filter: blur(4px);
    border: 1px solid rgba(255, 255, 255, 0.4);
    box-shadow: inset 0 2px 4px 0 rgba(0, 0, 0, 0.06);
}

.placeholder-icon {
    width: 2rem;
    height: 2rem;
    color: rgba(100, 116, 139, 0.7);
    /* slate-500/70 */
}

.placeholder-label {
    margin-top: 1rem;
    font-family: monospace;
    font-size: 0.875rem;
    color: #94a3b8;
    /* slate-400 */
    text-transform: uppercase;
    letter-spacing: 0.1em;
}

.gallery-real-img {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 700ms;
}

.gallery-visual-col:hover .gallery-real-img {
    transform: scale(1.05);
}

/* Dynamic BG Colors for placeholders */
.bg-stone-200 {
    background-color: #e7e5e4;
}

.bg-stone-300 {
    background-color: #d6d3d1;
}

/* Scroll Indicator */
.scroll-indicator {
    position: absolute;
    bottom: 0.5%;
    left: 50%;
    transform: translateX(-50%);
    z-index: 25;
    pointer-events: none;
    text-align: center;
    width: 100%;
}

.scroll-indicator p {
    font-family: 'Syncopate', sans-serif;
    font-size: 1rem;
    /* Increased significantly */
    color: rgba(255, 255, 255, 0.9);
    text-transform: uppercase;
    letter-spacing: 0.15em;
    animation: bounce 2s infinite;
    text-shadow: 0 2px 4px rgba(0, 0, 0, 0.6);
    margin: 0;
}

@keyframes bounce {

    0%,
    20%,
    50%,
    80%,
    100% {
        transform: translateY(0);
    }

    40% {
        transform: translateY(-6px);
    }

    60% {
        transform: translateY(-3px);
    }
}

