/* WorkshopGallery.css */

/* Define local variables for the "Shila" theme colors */
.workshop-gallery-section {
    --shila-gold: #D4AF37;
    --shila-gold-light: #F5E6BE;
    --shila-stone: #1c1917;
    --shila-mist: rgba(255, 255, 255, 0.5);

    position: relative;
    overflow: hidden;
    background: #ffffff;
    width: 100%;
    padding: 0;
}

.shared-smoke-overlay-wrapper {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: 0;
    /* Behind content but managed by Overlay logic */
}

/* Background Theme Arts */
.theme-art-container {
    position: absolute;
    pointer-events: none;
    z-index: 0;
    mix-blend-mode: multiply;
    opacity: 0.12;
    will-change: transform;
}

.theme-art-peacock {
    top: 5%;
    left: 0;
    width: 600px;
    height: 600px;
}

.theme-art-elephant {
    top: 40%;
    right: 0;
    width: 700px;
    height: 700px;
    opacity: 0.10;
}

.theme-art-temple {
    bottom: 0;
    left: 5%;
    width: 800px;
    height: 800px;
    opacity: 0.08;
}

.art-mask-wrapper {
    width: 100%;
    height: 100%;
    display: flex;
    align-items: center;
    justify-content: center;
}

.mask-fade-br {
    mask-image: linear-gradient(to bottom right, black 0%, transparent 70%);
    -webkit-mask-image: linear-gradient(to bottom right, black 0%, transparent 70%);
}

.mask-fade-l {
    mask-image: linear-gradient(to left, black 0%, transparent 70%);
    -webkit-mask-image: linear-gradient(to left, black 0%, transparent 70%);
}

.mask-fade-tr {
    mask-image: linear-gradient(to top right, black 0%, transparent 70%);
    -webkit-mask-image: linear-gradient(to top right, black 0%, transparent 70%);
}

.theme-image {
    width: 100%;
    height: 100%;
    object-fit: contain;
    filter: invert(1) sepia(0.2) hue-rotate(10deg);
}

.theme-peacock-transform {
    transform: translate(-25%, -25%);
}

.theme-elephant-transform {
    transform: translate(25%, 0);
}

.theme-temple-transform {
    transform: translate(0, 25%);
}


/* Main Container */
.workshop-container {
    position: relative;
    z-index: 10;
    padding: 0 2rem;
    max-width: 1400px;
    margin: 0 auto;
}

/* Gallery Row Layout */
.gallery-item-row {
    display: flex;
    align-items: stretch;
    /* CHANGED from center to stretch so visual col takes full height */
    justify-content: space-between;
    min-height: 110vh;
    padding: 1rem 0;
    gap: 4rem;
}

.gallery-item-row.reverse {
    flex-direction: row-reverse;
}

/* Text Column */
.gallery-text-col {
    flex: 1;
    display: flex;
    flex-direction: column;
    justify-content: center;
    /* Center text vertically since row stretches */
    align-items: flex-start;
    /* Prevent children (button) from stretching */
    padding: 2rem;
    max-width: 600px;
    z-index: 10;
}

/* ... (skip middle section) ... */

/* Visual Column */
.gallery-visual-col {
    flex: 1;
    position: relative;
    /* Important for absolute video positioning */
    display: flex;
    justify-content: center;
    align-items: center;
    /* Allow breakout */
    overflow: visible;
    /* Ensure it has height even if empty content because of stretch */
    min-height: 100%;
}

.gallery-title {
    font-family: var(--font-cinzel), serif;
    font-size: 3rem;
    /* 4xl approx */
    color: var(--shila-stone);
    font-weight: 400;
    margin-bottom: 1.5rem;
    line-height: 1.2;
}

.gallery-divider-container {
    height: 0.75rem;
    /* Reduced height for thinner line */
    width: 8rem;
    margin: 1rem 0;
    position: relative;
    overflow: visible;
    /* Allow smoke to billow naturally */
}

.gallery-divider-shader {
    width: 100%;
    height: 100%;
}

.gallery-desc {
    font-family: var(--font-inter), sans-serif;
    font-size: 1.125rem;
    /* lg */
    color: #374151;
    /* gray-700 */
    line-height: 1.625;
    /* relaxed */
    font-weight: 300;
    /* light */
}

/* Premium Button */
.gallery-cta-btn {
    position: relative;
    margin-top: 2rem;
    padding: 0.75rem 1.5rem;
    /* px-6 py-3 */
    overflow: visible;
    /* Changed to visible for smoke puff */
    border: none;
    /* Removed static border */
    border-radius: 9999px;
    /* rounded-full */
    background: transparent;
    cursor: pointer;
    transition: all 0.3s ease;
    /* Ensure it doesn't shrink */
    flex-shrink: 0;
}

.gallery-btn-shader {
    position: absolute;
    inset: -15px -20px;
    /* Asymmetric inset: Tighter height (-8px), Same width (-20px) */
    width: auto;
    height: auto;
    z-index: 0;
    pointer-events: none;
    border-radius: 9999px;
    /* Helpful for some browsers/clipping if needed */
}

.gallery-cta-btn:hover {
    /* Background removed as requested */
    background: transparent;
}

.gallery-btn-text {
    position: relative;
    z-index: 10;
    font-family: var(--font-cinzel), serif;
    color: var(--shila-stone);
    display: inline-block;
    transition: all 0.3s ease;
}

.gallery-cta-btn:hover .gallery-btn-text {
    letter-spacing: 0.1em;
    /* tracking-widest */
}


/* Visual Column */
.gallery-visual-col {
    flex: 1;
    position: relative;
    /* Important for absolute video positioning */
    display: flex;
    justify-content: center;
    align-items: center;
    /* Allow breakout */
    overflow: visible;
}

/* Video Wrapper - The Breakout Container */
.gallery-video-wrapper {
    position: absolute;
    top: -20%;
    /* Extend vertically for seamless flow */
    bottom: -20%;
    width: 65vw;
    /* Wide enough to reach edges on large screens */
    z-index: 0;
    /* Should be behind text (z:10) but above body bg */
    pointer-events: auto;
    will-change: transform, opacity;
    transform: translateZ(0);
}

/* Spinner */
.video-loading-spinner {
    position: absolute;
    inset: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    background: rgba(255, 255, 255, 0.1);
    z-index: 2;
    pointer-events: none;
    /* Let drag events pass through */
}

/* Debug Overlay */
.debug-overlay {
    position: absolute;
    top: 10px;
    left: 10px;
    background: rgba(0, 0, 0, 0.8);
    color: #00ff00;
    font-family: monospace;
    font-size: 12px;
    padding: 6px;
    border-radius: 4px;
    z-index: 100;
    pointer-events: auto;
    /* Enable clicks */
    border: 1px solid #00ff00;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.debug-controls {
    display: flex;
    gap: 4px;
    margin-top: 2px;
}

.debug-controls button {
    background: #333;
    color: #fff;
    border: 1px solid #555;
    font-size: 10px;
    cursor: pointer;
    padding: 2px 6px;
    border-radius: 2px;
}

.debug-controls button:hover {
    background: #555;
}

.spinner-ring {
    width: 40px;
    height: 40px;
    border: 3px solid rgba(212, 175, 55, 0.3);
    border-radius: 50%;
    border-top-color: #D4AF37;
    animation: spin 1s ease-in-out infinite;
}

@keyframes spin {
    to {
        transform: rotate(360deg);
    }
}

.gallery-video {
    width: 100%;
    height: 100%;
    object-fit: cover;
    object-position: center center;
    /* Force center alignment of video content */
    opacity: 0;
    transition: opacity 0.8s ease;
    filter: sepia(0.15) contrast(1.1);
    /* Subtle theme tint */
    border-radius: 0;
}

.gallery-video.visible {
    opacity: 0.9;
}

.gallery-video.hidden {
    opacity: 0;
}

/* Align Right (For Text Left, Image Right layouts) */
/* Fade Left + Top + Bottom */
.gallery-video-wrapper.video-align-right {
    left: -10%;
    /* Combine masks: 
       1. Fade Left Edge (Gradient to right)
       2. Fade Top/Bottom (Gradient to vertical center)
       Updated for Scale ~0.8 videos: Pushed fade zones in to 12% to cover video edges (10%)
    */
    mask-image:
        linear-gradient(to right, transparent 12%, black 30%, black 100%),
        linear-gradient(to bottom, transparent 12%, black 30%, black 70%, transparent 88%);
    mask-composite: intersect;
    /* Only show where BOTH are opaque (standard) or use specific webkit */
    -webkit-mask-image:
        linear-gradient(to right, transparent 12%, black 30%, black 100%),
        linear-gradient(to bottom, transparent 12%, black 30%, black 70%, transparent 88%);
    -webkit-mask-composite: source-in;
    /* standard intersection */
}

/* Align Left (For Text Right, Image Left layouts) */
/* Fade Right + Top + Bottom */
.gallery-video-wrapper.video-align-left {
    right: -10%;
    mask-image:
        linear-gradient(to left, transparent 0%, black 20%, black 100%),
        linear-gradient(to bottom, transparent 0%, black 15%, black 85%, transparent 100%);
    mask-composite: intersect;
    -webkit-mask-image:
        linear-gradient(to left, transparent 0%, black 20%, black 100%),
        linear-gradient(to bottom, transparent 0%, black 15%, black 85%, transparent 100%);
    -webkit-mask-composite: source-in;
}


/* Optional: Overlay gradient if text needs more contrast (though text is in other col) */
.video-overlay-gradient {
    position: absolute;
    inset: 0;
    background: linear-gradient(to bottom, transparent 0%, rgba(255, 255, 255, 0.2) 100%);
    mix-blend-mode: overlay;
    opacity: 0.5;
}

/* --- Cleaned up Old Card Styles --- */
/* (Removed gallery-media-card, icon-circle, specific placeholders, etc.) */

/* Helper for responsiveness: On mobile, stack changes */
@media (max-width: 1024px) {
    .workshop-gallery-section {
        padding-bottom: 0 !important;
        margin-bottom: 0 !important;
        height: auto !important;
        /* Let it shrink fit */
        min-height: auto !important;
    }

    .workshop-container {
        padding: 0 !important;
        margin: 0 !important;
        width: 100%;
        max-width: 100%;
    }

    /* Maintain side-by-side layout (same as desktop but tiny) */
    .gallery-item-row {
        flex-direction: row;
        /* Allow standard alternating behavior via existing .reverse class */
        /* STRICT 100vh LAYOUT */
        height: 100vh;
        min-height: 100vh;
        margin-bottom: 0;
        padding: 0;
        gap: 0;
        align-items: stretch;
        /* Stretch columns to full height */
        overflow: hidden;
    }

    .gallery-item-row.reverse {
        flex-direction: row-reverse;
    }

    /* Text Column - Shrink everything */
    .gallery-text-col {
        flex: 1;
        width: 60%;
        /* Wider text area */
        max-width: 60%;
        padding: 0 0.5rem;
        /* Slight horizontal padding */
        /* minimal padding */
        z-index: 10;
        align-items: flex-start;
        /* Reset from center */
        text-align: left;
    }

    .gallery-title {
        font-size: 1.8rem;
        /* Larger title */
        margin-bottom: 0.5rem;
    }

    .gallery-divider-container {
        width: 6rem;
        /* Increased width */
        height: 0.75rem;
        /* Restored height for smoke flow */
        margin: 1rem 0 1.5rem 0;
        /* Added bottom margin */
        position: relative;
    }

    .gallery-desc {
        font-size: 1rem;
        /* Readable description */
        line-height: 1.4;
    }

    .gallery-cta-btn {
        margin-top: 1rem;
        padding: 0.5rem 1.2rem;
        position: relative;
        left: 8px;
        /* Ensure context */
    }

    .gallery-btn-text {
        font-size: 0.75rem;
    }

    .gallery-btn-shader {
        /* Standardize position relative to button */
        position: absolute;
        inset: -6px -20px;
        /* Asymmetric inset: Tighter height (-6px), Standard width (-20px) */
        width: auto !important;
        height: auto !important;
        transform: none;
        /* Remove transform to avoid coordinate mismatch */
        opacity: 1;
        /* Full visibility */
    }

    /* Visual Column - Adjust video sizes */
    .gallery-visual-col {
        flex: 1;
        width: 40%;
        max-width: 40%;
        height: auto;
        opacity: 1;
        overflow: visible;
        display: flex;
        justify-content: center;
        align-items: center;
    }

    .gallery-video-wrapper {
        width: 200%;
        height: 100%;
        position: absolute;
        top: 0;
        bottom: 0;
        left: auto !important;
        right: auto !important;
        z-index: 0;
    }

    /* Text Left, Video Right */
    .gallery-item-row:not(.reverse) .gallery-video-wrapper {
        width: 200% !important;
        left: auto !important;
        right: -20% !important;
        /* Shift right to stick subject to edge */
        /* Adjust mask to fade in from screen left (which is ~15% into wrapper) */
        mask-image: linear-gradient(to right, transparent 15%, black 45%, black 100%);
        -webkit-mask-image: linear-gradient(to right, transparent 15%, black 45%, black 100%);
    }

    /* Text Right, Video Left */
    .gallery-item-row.reverse .gallery-video-wrapper {
        width: 200% !important;
        left: -20% !important;
        /* Shift left to adjust subject position */
        right: auto !important;
        /* Symmetric mask to the other video: fade in from right (screen center) */
        mask-image: linear-gradient(to left, transparent 15%, black 45%, black 100%);
        -webkit-mask-image: linear-gradient(to left, transparent 15%, black 45%, black 100%);
    }

    /* Specific padding for Text-Left rows - Stick to extreme left */
    .gallery-item-row:not(.reverse) .gallery-text-col {
        padding-left: 4px;
        padding-right: 0.5rem;
        background: linear-gradient(to right, rgba(255, 255, 255, 1) 40%, rgba(255, 255, 255, 0.5) 80%, transparent 100%);
    }

    .gallery-item-row.reverse .gallery-text-col {
        background: linear-gradient(to left, rgba(255, 255, 255, 1) 40%, rgba(255, 255, 255, 0.5) 80%, transparent 100%);
        padding-left: 0.5rem;
    }

    /* Resize Background Arts for Mobile */
    .theme-art-peacock {
        width: 300px;
        height: 300px;
        top: 10%;
        /* Moved down */
        opacity: 0.25;
        /* Increased visibility significantly */
    }

    .theme-art-elephant {
        width: 350px;
