.gallery-visual-col:hover .gallery-media-container {
    box-shadow: 0 20px 50px -12px rgba(164, 213, 255, 0.4);
}

/* Placeholders */
.gallery-placeholder-inner {
    position: absolute;
    inset: 0;
    display: flex;
    align-items: center;
    justify-content: center;
}

.placeholder-icon-box {
    display: inline-block;
    padding: 1rem;
    border-radius: 9999px;
    background-color: rgba(255, 255, 255, 0.3);
